.darma-loader-darma-custom-444 {color: var(--loader-color, #f97316);
   width: 65px;
   aspect-ratio: 1;
   position: relative;
}
.darma-loader-darma-custom-444:before, .darma-loader-darma-custom-444:after  {
  content: "";
   position: absolute;
   inset: 0 auto auto 0;
   aspect-ratio: 1;
   border-radius: 50px;
   box-shadow: 0 0 0 3px inset currentColor;
   animation: darma-loader-darma-custom-444-l5 1s infinite linear alternate;
}
.darma-loader-darma-custom-444:after  {
  inset: auto 0 0 auto;
   animation-delay: -1s;
}
@keyframes darma-loader-darma-custom-444-l5  {
  0%  {
  width: 20px;
}
100%  {
  width: 50px;
}
}

